"use client"

import React, { useState, useEffect } from 'react';
import KakaoMap from '@/components/map/KakaoMap'; // 위에서 만든 지도 컴포넌트 [cite: 2026-02-19]
import api from '@/util/api'; // axios 설정 파일 [cite: 2026-02-18]

// 1. 시/도 및 시/군/구 데이터 (예시입니다. 더 추가 가능합니다) [cite: 2026-02-04]
const REGION_DATA: { [key: string]: string[] } = {
  "서울특별시": ["강남구", "강동구", "강북구", "강서구", "관악구", "마포구", "서초구", "서대문구"],
  "경기도": ["수원시", "성남시", "의정부시", "안양시", "부천시", "광명시"],
  "경상남도": ["진주시", "창원시", "김해시", "양산시"]
};

// 2. 지역별 중심 좌표 (지도를 해당 지역으로 이동시키기 위함) [cite: 2026-02-19]
const REGION_COORDS: { [key: string]: { lat: number; lng: number } } = {
  "서울특별시": { lat: 37.5665, lng: 126.9780 },
  "마포구": { lat: 37.5637, lng: 126.9084 },
  "강남구": { lat: 37.4979, lng: 127.0276 },
  "진주시": { lat: 35.1795, lng: 128.1076 }
};

export default function PharmacyPage() {
  const [city, setCity] = useState("");
  const [district, setDistrict] = useState("");
  const [pharmacyList, setPharmacyList] = useState([]);
  const [centerPos, setCenterPos] = useState({ lat: 37.5665, lng: 126.9780 });

  // 🚀 지역 선택 시 약국 데이터 가져오기 [cite: 2026-02-16, 2026-02-18]
  const fetchPharmacies = async (selectedCity: string, selectedDistrict: string) => {
    if (!selectedCity || !selectedDistrict) return;
    
    try {
      // 백엔드의 findByRegion API 호출 [cite: 2026-02-16, 2026-02-18]
      const response = await api.get(`/api/pharmacies/region`, {
        params: { city: selectedCity, district: selectedDistrict }
      });
      setPharmacyList(response.data);

      // 해당 지역의 중심 좌표로 지도 이동 설정 (좌표 데이터가 있다면) [cite: 2026-02-19]
      if (REGION_COORDS[selectedDistrict]) {
        setCenterPos(REGION_COORDS[selectedDistrict]);
      } else if (REGION_COORDS[selectedCity]) {
        setCenterPos(REGION_COORDS[selectedCity]);
      }
    } catch (error) {
      console.error("약국 정보를 가져오는데 실패했습니다.", error);
    }
  };

  return (
    <div style={{ padding: '20px' }}>
      <h1>전국 약국 찾기 (지역별 검색)</h1>
      
      {/* 🚀 지역 선택 UI */}
      <div style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
        <select value={city} onChange={(e) => { setCity(e.target.value); setDistrict(""); }}>
          <option value="">시/도 선택</option>
          {Object.keys(REGION_DATA).map(c => <option key={c} value={c}>{c}</option>)}
        </select>

        <select 
          value={district} 
          onChange={(e) => {
            setDistrict(e.target.value);
            fetchPharmacies(city, e.target.value); // 구를 선택하면 바로 검색 [cite: 2026-02-18, 2026-02-19]
          }}
          disabled={!city}
        >
          <option value="">시/군/구 선택</option>
          {city && REGION_DATA[city].map(d => <option key={d} value={d}>{d}</option>)}
        </select>
      </div>

      {/* 🚀 지도 컴포넌트에 데이터 전달 [cite: 2026-02-19] */}
      <div style={{ width: '100%', height: '600px', border: '1px solid #ccc' }}>
        <KakaoMap pharmacyList={pharmacyList} centerPos={centerPos} />
      </div>
    </div>
  );
}